import React, { useState, useEffect, useRef } from 'react';

const images = [
  '/images/screen-1.jpg',
  '/images/screen-2.jpg',
  '/images/screen-3.jpg',
  '/images/screen-4.jpg',
  '/images/screen-5.jpg',
];

const labels2 = ['Web bán hàng', 'Web bất động sản', 'App quản lý nhân sự', 'Bot Telegram', 'Quản lý giao hàng'];

function ShowcaseSection2() {
  const [currentImage, setCurrentImage] = useState(0);
  const [imgVisible, setImgVisible] = useState(true);
  const [vidIndex, setVidIndex] = useState(0);
  const [vidShow, setVidShow] = useState(true);
  const [labelIdx, setLabelIdx] = useState(0);
  const [labelShow, setLabelShow] = useState(true);
  const v1 = useRef(null);
  const v2 = useRef(null);

  useEffect(() => {
    const id = setInterval(() => {
      setImgVisible(false);
      setTimeout(() => {
        setCurrentImage(p => (p + 1) % images.length);
        setTimeout(() => setImgVisible(true), 80);
      }, 350);
    }, 2800);
    return () => clearInterval(id);
  }, []);

  useEffect(() => {
    const id = setInterval(() => {
      setLabelShow(false);
      setTimeout(() => {
        setLabelIdx(p => (p + 1) % labels2.length);
        setTimeout(() => setLabelShow(true), 80);
      }, 350);
    }, 2000);
    return () => clearInterval(id);
  }, []);

  function onV1End() {
    setVidShow(false);
    setTimeout(() => {
      setVidIndex(1);
      setTimeout(() => {
        setVidShow(true);
        setTimeout(() => {
          if (v2.current) { v2.current.currentTime = 0; v2.current.play().catch(() => {}); }
        }, 50);
      }, 100);
    }, 400);
  }

  function onV2Time() {
    if (v2.current && v2.current.currentTime >= 10) {
      v2.current.pause();
      setVidShow(false);
      setTimeout(() => {
        setVidIndex(0);
        setTimeout(() => {
          setVidShow(true);
          setTimeout(() => {
            if (v1.current) { v1.current.currentTime = 0; v1.current.play().catch(() => {}); }
          }, 50);
        }, 100);
      }, 400);
    }
  }

  return (
    <section className="pt-0 pb-10 px-4 sm:px-6 lg:px-8 bg-white overflow-hidden">
      <style>{`
        @keyframes rvIn2 { from { clip-path: inset(50% 50% 50% 50% round 12px); } to { clip-path: inset(0 0 0 0 round 12px); } }
        @keyframes rvOut2 { from { clip-path: inset(0 0 0 0 round 12px); } to { clip-path: inset(50% 50% 50% 50% round 12px); } }
      `}</style>
      <div className="max-w-screen-xl mx-auto">
        {/* Wrapper with sphere behind */}
        <div className="relative">
          {/* Sphere glow behind TV */}
          <div className="absolute pointer-events-none" style={{ width: '120%', height: '130%', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', zIndex: 0 }}>
            <div className="absolute inset-0 rounded-full" style={{ background: 'radial-gradient(circle, rgba(8,15,40,0.95) 0%, rgba(10,20,55,0.85) 25%, rgba(15,30,70,0.5) 45%, rgba(20,40,90,0.2) 60%, transparent 75%)' }} />
            <div className="absolute inset-0 rounded-full" style={{ background: 'radial-gradient(circle at 30% 30%, rgba(0,100,255,0.12) 0%, transparent 50%)' }} />
            <div className="absolute inset-0 rounded-full" style={{ background: 'radial-gradient(circle at 65% 55%, rgba(139,92,246,0.1) 0%, transparent 40%)' }} />
            <div className="absolute inset-0 rounded-full opacity-40" style={{ backgroundImage: 'radial-gradient(rgba(255,255,255,0.08) 1px, transparent 1px)', backgroundSize: '14px 14px', mask: 'radial-gradient(circle, black 20%, transparent 50%)', WebkitMask: 'radial-gradient(circle, black 20%, transparent 50%)' }} />
          </div>

          {/* TV Frame */}
          <div className="relative rounded-3xl p-6 lg:p-10" style={{
            background: 'linear-gradient(135deg, #0a1628 0%, #0f2847 30%, #0c1a33 60%, #091420 100%)',
            boxShadow: '0 25px 80px rgba(0,0,0,0.35), 0 0 40px rgba(56,189,248,0.08), 0 0 80px rgba(59,130,246,0.05), inset 0 1px 0 rgba(255,255,255,0.08)',
            border: '1px solid rgba(56,189,248,0.15)',
            zIndex: 1,
          }}>
            {/* Floating label */}
            <div className="absolute top-5 left-7 z-20">
              <span className="text-white/90 font-semibold text-lg px-4 py-2 rounded-xl inline-block" style={{
                background: 'linear-gradient(135deg, rgba(139,92,246,0.3), rgba(56,189,248,0.3))',
                backdropFilter: 'blur(8px)',
                border: '1px solid rgba(255,255,255,0.1)',
                opacity: labelShow ? 1 : 0,
                transform: labelShow ? 'translateY(0)' : 'translateY(-8px)',
                transition: 'opacity 0.3s ease, transform 0.3s ease',
              }}>
                {labels2[labelIdx]}
              </span>
            </div>

            <div className="flex flex-col lg:flex-row gap-6 items-center justify-center">
              <div className="w-full lg:w-3/5" style={{
                animation: vidShow ? 'rvIn2 0.4s ease-out forwards' : 'rvOut2 0.3s ease-in forwards',
              }}>
                {vidIndex === 0 && (
                  <div className="rounded-xl overflow-hidden" style={{ aspectRatio: '16/9' }}>
                    <video ref={v1} className="w-full h-full object-cover" autoPlay muted playsInline onEnded={onV1End} src="/videos/map-manager.mp4" />
                  </div>
                )}
                {vidIndex === 1 && (
                  <div className="rounded-xl overflow-hidden mx-auto" style={{ aspectRatio: '9/19', maxHeight: '600px' }}>
                    <video ref={v2} className="w-full h-full object-cover" muted playsInline onTimeUpdate={onV2Time} src="/videos/video-ship-manager.mp4" />
                  </div>
                )}
              </div>

              <div className="w-full lg:w-2/5 flex justify-center">
                <div style={{ position: 'relative', aspectRatio: '9/19', maxHeight: '600px' }}>
                  {images.map((src, i) => (
                    <img key={i} src={src} alt="App screenshot" className="rounded-xl" style={{
                      position: i === 0 ? 'relative' : 'absolute',
                      top: 0, left: 0, width: '100%', height: '100%', objectFit: 'cover',
                      opacity: i === currentImage && imgVisible ? 1 : 0,
                      transform: i === currentImage && imgVisible ? 'scale(1)' : 'scale(0.85)',
                      transition: 'opacity 0.35s ease, transform 0.35s ease',
                    }} />
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default ShowcaseSection2;
